    rate_percent = float(rate_percent)
    seller = str(seller_state_code).strip()
    buyer = str(buyer_state_code).strip()
    if seller == buyer:
        half = round(amount * rate_percent / 200.0, 2)
        return {"cgst": half, "sgst": half, "igst": 0.0}
    else:
        igst = round(amount * rate_percent / 100.0, 2)
        return {"cgst": 0.0, "sgst": 0.0, "igst": igst}

