        return "zero"

    groups = ["", "thousand", "million", "billion", "trillion"]
    chunks = []
    while n > 0:
        chunks.append(n % 1000)
        n //= 1000
    res = []
    for idx in range(len(chunks) - 1, -1, -1):
        c = chunks[idx]
        if c:
            seg = three(c)
            if groups[idx]:
                seg = seg + " " + groups[idx]
            res.append(seg)
    return " ".join(res)

