import re

STATE_CODES = {
    "AN","AP","AR","AS","BR","CH","CG","DD","DL","DN","GA","GJ","HR","HP",
    "JK","JH","KA","KL","LA","LD","MH","ML","MN","MP","MZ","NL","OD","OR",
    "PB","PY","RJ","SK","TN","TR","TS","UK","UP","WB",
}

_STD = re.compile(r'^([A-Z]{2})(\d{1,2})([A-Z]{1,3})(\d{1,4})$')
_BH = re.compile(r'^(\d{2})BH(\d{4})([A-Z]{1,2})$')


def is_valid_plate(s):
    if not isinstance(s, str):
        return False
    if s != s.upper() or ' ' in s:
        return False
    if _BH.match(s):
        return True
    m = _STD.match(s)
    if m:
        return m.group(1) in STATE_CODES
    return False

