def fy_and_quarter(date_str):
    from datetime import date
    d = date.fromisoformat(date_str)
    y, m = d.year, d.month
    if m >= 4:
        start = y
        quarter = (m - 4) // 3 + 1
    else:
        start = y - 1
        quarter = 4
    fy = "{}-{:02d}".format(start, (start + 1) % 100)
    return (fy, quarter)

import hmac
import hashlib


def verify_signature(payload_body, signature, secret):
    expected = hmac.new(
        secret.encode("utf-8"),
        payload_body.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()
    return hmac.compare_digest(expected, signature)

def is_valid_cin(s):
    if not isinstance(s, str):
        return False
    if len(s) != 21:
        return False
    if not s.isalnum():
        return False
    if s != s.upper():
        return False
    # [1] listing status: L (listed) or U (unlisted)
    if s[0] not in ('L', 'U'):
        return False
    # [2-6] industry code: 5 digits
    if not s[1:6].isdigit():
        return False
    # [7-8] state/RoC code: 2 letters from a known set
    VALID_STATES = {
        'AP','AR','AS','BR','CG','CH','DD','DL','DN','GA','GJ','HP','HR','JH',
        'JK','KA','KL','LD','MH','ML','MN','MP','MZ','NL','OR','PB','PY','RJ',
        'SK','TG','TN','TR','UK','UP','UR','WB','AN',
    }
    state = s[6:8]
    if not state.isalpha() or state not in VALID_STATES:
        return False
    # [9-12] year of incorporation: 4 digits, plausible range
    if not s[8:12].isdigit():
        return False
    year = int(s[8:12])
    if year < 1857 or year > 2026:
        return False
    # [13-15] ownership / company-type code: 3 letters from a known set
    VALID_TYPES = {
        'PLC','PTC','OPC','NPL','FLC','FTC','GOI','SGC','GAP','GAT','ULL','ULT',
    }
    ctype = s[12:15]
    if not ctype.isalpha() or ctype not in VALID_TYPES:
        return False
    # [16-21] registration number: 6 digits
    if not s[15:21].isdigit():
        return False
    return True

