def is_valid_card(num):
    if not isinstance(num, str):
        return False
    if len(num) != 16 or not num.isdigit():
        return False
    total = 0
    for i, ch in enumerate(reversed(num)):
        d = int(ch)
        if i % 2 == 1:
            d *= 2
            if d > 9:
                d -= 9
        total += d
    if total % 10 != 0:
        return False
    rupay_prefixes = ("60", "65", "81", "82", "508")
    return num.startswith(rupay_prefixes)

