def compute_total(items, delivery_fee, platform_fee, tip):
    subtotal = 0.0
    for it in items:
        line = it["price"] * it["qty"] * (1 + it["gst_rate"] / 100.0)
        subtotal += line
    total = subtotal + delivery_fee + platform_fee + tip
    return round(total, 2)

